sys_script.script:
(function executeRule(current, previous) {

    try {

        // ================================
        // 1. Fetch Plan
        // ================================
        var planGR = new GlideRecord('x_ctans_incentnow_plan');

         if (!planGR.get(current.x_ctans_incentnow_plan)) {
             return;
         }

        var planStatus = planGR.getValue('status');

        // ================================
        // 2. BLOCK NON-ACTIVE PLAN ASSIGNMENT
        // ================================
        if (planStatus != 'active') {

            gs.addErrorMessage(
                "Only ACTIVE plans can be assigned to users. " +
                "Please activate the plan before assignment."
            );

            current.setAbortAction(true);
            return;
        }

        // ================================
        // 3. CHECK EXISTING ACTIVE PLAN
        // ================================

        var existing = new GlideRecord('x_ctans_incentnow_plan_users');
        existing.addQuery('x_ctans_incentnow_sales_user', current.x_ctans_incentnow_sales_user);
        existing.addQuery('sys_id', '!=', current.sys_id);
        existing.query();

        while (existing.next()) {

            var existingPlanGR = new GlideRecord('x_ctans_incentnow_plan');

            if (existingPlanGR.get(existing.x_ctans_incentnow_plan)) {

                if (existingPlanGR.getValue('status') == 'active') {

                    gs.addErrorMessage(
                        "User already has an active plan assigned: " +
                        existingPlanGR.getDisplayValue() +
                        ". Please deactivate it or remove existing assignment before assigning a new plan."
                    );

                    current.setAbortAction(true);
                    return;
                }
            }
        }

    } catch (ex) {

        gs.addErrorMessage("Validation failed: " + ex.message);
        current.setAbortAction(true);
    }

})(current, previous);
